import{P as e}from"./chunks/ProjectHome.4QpGWHnZ.js";import{c as t,o,G as n,k as i}from"./chunks/framework.DILC4Csi.js";import"./chunks/theme.CgzSYMVu.js";const c={name:"opencode-notify",tagline:"Пусть OpenCode AI мягко напоминает вам, когда вы сосредоточены",description:"Попрощайтесь с тревогой постоянного переключения окон. opencode-notify предоставляет нативные уведомления на рабочем столе для вашего OpenCode AI с интеллектуальным обнаружением фокуса, тихими часами и кликом для фокусировки (macOS), позволяя вам работать сосредоточенно и пробуждаться точно, когда AI нуждается в вас.",github_url:"https://github.com/kdcokenny/opencode-notify"},d={primary_action:{text:"Быстрый старт",link:"/ru/kdcokenny/opencode-notify/start/quick-start/"}},s={title:"Почему стоит выбрать opencode-notify?",subtitle:"Сосредоточенная работа, интеллектуальные напоминания",list:[{title:"🔔 Нативные уведомления на рабочем столе",desc:"Использует нативную систему уведомлений операционной системы (macOS Notification Center, Windows Toast, Linux notify-send), бесшовно интегрируясь в ваш рабочий процесс."},{title:"🧠 Интеллектуальное обнаружение фокуса",desc:"Автоматически обнаруживает фокус окна терминала, избегая повторяющихся уведомлений. По умолчанию уведомляет только родительскую сессию, фильтруя шум от дочерних задач, позволяя вам сосредоточиться на действительно важной информации."},{title:"⏰ Настройка тихих часов",desc:"Установите периоды тишины (например, 22:00-08:00), ночью автоматически подавляются уведомления, поддерживаются периоды через полночь, гарантируя ваше время отдыха."},{title:"🖱️ Клик для фокусировки терминала (macOS)",desc:"Пользователи macOS могут автоматически фокусировать окно терминала одним кликом по уведомлению, экономя время на переключение приложений и удваивая производительность."},{title:"🎨 Пользовательские звуки (macOS)",desc:"Устанавливайте уникальные звуки для различных типов событий (Glass, Basso, Submarine и другие), быстро распознавая тип уведомления по звуку."},{title:"💻 Поддержка 37+ терминалов",desc:"Поддержка Ghostty, iTerm2, WezTerm, VS Code интегрированного терминала и более 37 эмуляторов терминала, автоматически распознавая тип вашего терминала."},{title:"🔒 Локальный запуск, нулевой риск конфиденциальности",desc:"Все уведомления генерируются локально, данные не загружаются в облако, ваш рабочий контент полностью конфиденциален и безопасен."},{title:"⚡ Легковесный плагин",desc:"Построен на TypeScript + Bun, установка и использование из коробки, конфигурационный файл лаконичен, не требуется изучать сложную конфигурацию."}]},a={title:"План курса",subtitle:"Всего 4 раздела, 12 уроков",sections:[{title:"Введение (Start)",items:[{title:"Быстрый старт",desc:"Помогает пользователям завершить установку за 5 минут и испытать первое уведомление",link:"/ru/kdcokenny/opencode-notify/start/quick-start/"},{title:"Как это работает",desc:"Объясняет основные функции плагина, механизм интеллектуальной фильтрации и условия срабатывания уведомлений",link:"/ru/kdcokenny/opencode-notify/start/how-it-works/"}]},{title:"Платформенные функции (Platforms)",items:[{title:"Особенности платформы macOS",desc:"Введение в полный функционал платформы macOS (обнаружение фокуса, клик для фокусировки, пользовательские звуки)",link:"/ru/kdcokenny/opencode-notify/platforms/macos/"},{title:"Особенности платформы Windows",desc:"Введение в функционал платформы Windows (нативные уведомления, обнаружение терминала)",link:"/ru/kdcokenny/opencode-notify/platforms/windows/"},{title:"Особенности платформы Linux",desc:"Введение в функционал платформы Linux (нативные уведомления, обнаружение терминала)",link:"/ru/kdcokenny/opencode-notify/platforms/linux/"},{title:"Поддерживаемые терминалы",desc:"Список всех поддерживаемых эмуляторов терминала (37+ терминалов)",link:"/ru/kdcokenny/opencode-notify/platforms/terminals/"}]},{title:"Продвинутые функции (Advanced)",items:[{title:"Справочник по конфигурации",desc:"Предоставляет полное описание параметров конфигурации и примеры",link:"/ru/kdcokenny/opencode-notify/advanced/config-reference/"},{title:"Подробно о тихих часах",desc:"Объясняет, как настроить периоды тишины, чтобы избежать уведомлений в определенное время",link:"/ru/kdcokenny/opencode-notify/advanced/quiet-hours/"},{title:"Принцип обнаружения терминала",desc:"Объясняет механизм автоматического обнаружения терминала и как вручную указать тип терминала",link:"/ru/kdcokenny/opencode-notify/advanced/terminal-detection/"},{title:"Продвинутое использование",desc:"Предоставляет советы по конфигурации и лучшие практики",link:"/ru/kdcokenny/opencode-notify/advanced/advanced-usage/"}]},{title:"Часто задаваемые вопросы (FAQ)",items:[{title:"Устранение неполадок",desc:"Решение распространенных проблем (уведомления не отображаются, обнаружение фокуса не работает, ошибки конфигурации и т.д.)",link:"/ru/kdcokenny/opencode-notify/faq/troubleshooting/"},{title:"Часто задаваемые вопросы",desc:"Ответы на часто задаваемые вопросы пользователей (влияние на производительность, конфиденциальность и безопасность, конфликты плагинов и т.д.)",link:"/ru/kdcokenny/opencode-notify/faq/common-questions/"}]}]},r={project:c,hero:d,features:s,docs:a},h=JSON.parse('{"title":"opencode-notify","description":"Позвольте OpenCode AI нежно напоминать вам во время сосредоточенной работы","frontmatter":{"layout":"page","pageClass":"project-home-page","sidebar":false,"title":"opencode-notify","sidebarTitle":"Нежные напоминания при концентрации","description":"Позвольте OpenCode AI нежно напоминать вам во время сосредоточенной работы"},"headers":[],"relativePath":"ru/kdcokenny/opencode-notify/index.md","filePath":"ru/kdcokenny/opencode-notify/index.md"}'),l={name:"ru/kdcokenny/opencode-notify/index.md"},_=Object.assign(l,{setup(k){return(p,u)=>(o(),t("div",null,[n(e,{data:i(r)},null,8,["data"])]))}});export{h as __pageData,_ as default};
